import { mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const sourceFiles = [
  'games/fridge-overflow/src/config.js',
  'games/fridge-overflow/src/board-model.js',
  'games/fridge-overflow/src/clear-resolver.js',
  'games/fridge-overflow/src/game.js',
];
const outputFile = 'games/fridge-overflow/src/game.bundle.js';

function transform(source) {
  return source
    .replace(/import[\s\S]*?from ['"][^'"]+['"];\n/g, '')
    .replace(/export const /g, 'const ')
    .replace(/export function /g, 'function ');
}

const chunks = sourceFiles.map((file) => {
  const source = readFileSync(join(root, file), 'utf8');
  return `\n// Source: ${file}\n${transform(source)}`;
});

const output = `// Generated by scripts/build-fridge-overflow-bundle.mjs. Do not edit manually.\n(() => {\n'use strict';\n${chunks.join('\n')}\n})();\n`;

mkdirSync(dirname(join(root, outputFile)), { recursive: true });
writeFileSync(join(root, outputFile), output);
